export const LS = {
  get: (k) => { try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : null; } catch { return null; } },
  set: (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); return true; } catch { return false; } }
};

export const san = (d) => JSON.parse(JSON.stringify(d));

// Formata um número para Moeda Brasileira (R$)
export const fmtR = (v) => `R$ ${Number(v || 0).toFixed(2).replace(".", ",")}`;

// Formata Data de YYYY-MM-DD para DD/MM/YYYY
export const fmtDt = (d) => { if (!d) return "—"; const [y, m, day] = d.split("-"); return `${day}/${m}/${y}`; };

// Pega a data de hoje formatada
export const today = () => new Date().toISOString().split("T")[0];

// Gera um ID único e aleatório para os itens do carrinho
export const generateId = () => Math.random().toString(36).substr(2, 9);

// Calcula o preço de UM bolo (Preço Base do Tamanho + Preço dos Adicionais)
export const calcItem = (item) => {
  let total = Number(item.precoBase || 0);
  
  if (item.adicionais && item.adicionais.length > 0) {
    item.adicionais.forEach(adic => {
      total += Number(adic.preco || 0);
    });
  }
  
  return total;
};

// Calcula o valor total de todos os itens do carrinho juntos
export const calcTotal = (cart) => {
  if (!cart || cart.length === 0) return 0;
  return cart.reduce((acc, item) => acc + calcItem(item), 0);
};

// Gera um código de identificação curto e bonito para o cliente (Ex: #FB-A9X2)
export const gerarCodigoPedido = () => {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let result = '';
  for (let i = 0; i < 4; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return `#FB-${result}`;
};
